    if (props.category === 'like') {
        // special case for likes
        return (React.createElement(Sidebar, null,
            React.createElement(Categories, { mode: 'view' }),
            React.createElement("section", { className: 'data-section' },
                React.createElement("header", { className: `section-header view ${props.category} background-${props.category}` },
                    React.createElement("h2", { className: "h2" }, "Like me!")),
                React.createElement("form", { className: 'buttons-container' },
                    React.createElement(InfoBox, { msg: 'Click all the buildings that you like and think contribute to the city!' }),
                    React.createElement(Link, { to: '/view/like', className: 'btn btn-secondary' }, "Back to view"),
                    React.createElement(Link, { to: '/edit/like', className: 'btn btn-secondary' }, "Back to edit")))));
    }
    let data = parseJsonOrDefault(props.dataString);
    let error;
    if (data == null) {
        error = 'Invalid parameters supplied';
        data = {};
    }
    else if (Object.values(data).some(x => x == undefined)) {
        error = 'Cannot copy empty values';
        data = {};
    }
    return (React.createElement(Sidebar, null,
        React.createElement(Categories, { mode: 'view' }),
        React.createElement("section", { className: 'data-section' },
            React.createElement("header", { className: `section-header view ${props.category} background-${props.category}` },
                React.createElement("h2", { className: "h2" },
                    "Copy ",
                    props.category,
                    " data")),
            React.createElement("div", { className: "section-body" },
                React.createElement("form", null,
                    error ?
                        React.createElement(ErrorBox, { msg: error }) :
                        React.createElement(InfoBox, { msg: 'Click buildings one at a time to colour using the data below' }),
                    Object.keys(data).map((key => {
                        const info = dataFields[key] || {};
                        return (React.createElement(DataEntry, { title: info.title || `Unknown field (${key})`, slug: key, disabled: true, value: data[key] }));
                    }))),
                React.createElement("form", { className: 'buttons-container' },
                    React.createElement(Link, { to: `/view/${props.category}`, className: 'btn btn-secondary' }, "Back to view"),
                    React.createElement(Link, { to: `/edit/${props.category}`, className: 'btn btn-secondary' }, "Back to edit"))))));
};
export default MultiEdit;
